vector<int> bfs(vector<vector<int>>& adj) {
int V = adj.size();
vector<bool> visited(V, false);
vector<int> res;

queue<int> q;

int src = 0;
visited[src] = true;
q.push(src);

while (!q.empty()) {
int curr = q.front();
q.pop();
res.push_back(curr);

for (int x : adj[curr]) {
if (!visited[x]) {
visited[x] = true;
q.push(x);
}
}
}

return res;
}

vector<int> dijkstra(vector<vector<pair<int,int>>>& adj, int src) {

int V = adj.size();

priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

vector<int> dist(V, INT_MAX);

dist[src] = 0;
pq.emplace(0, src);

while (!pq.empty()) {
auto top = pq.top();
pq.pop();

int d = top.first;
int u = top.second;

if (d > dist[u])
continue;

for (auto &p : adj[u]) {
int v = p.first;
int w = p.second;

if (dist[u] + w < dist[v]) {
dist[v] = dist[u] + w;
pq.emplace(dist[v], v);
}
}
}

return dist;
}

