vector<int> topologicalSort(int V, vector<vector<int>>& adj) {
vector<int> indegree(V, 0);

for (int u = 0; u < V; u++)
for (int v : adj[u])
indegree[v]++;

queue<int> q;

for (int i = 0; i < V; i++)
if (indegree[i] == 0)
q.push(i);

vector<int> topo;

while (!q.empty()) {
int u = q.front();
q.pop();

topo.push_back(u);

for (int v : adj[u]) {
indegree[v]--;

if (indegree[v] == 0)
q.push(v);
}
}

return topo;
}

