void bubbleSort(vector<int>& arr) {
int n = arr.size();
bool swapped;

for (int i = 0; i < n - 1; i++) {
swapped = false;

for (int j = 0; j < n - i - 1; j++) {
if (arr[j] > arr[j + 1]) {
swap(arr[j], arr[j + 1]);
swapped = true;
}
}

if (!swapped)
break;
}
}

void selectionSort(vector<int>& arr) {
int n = arr.size();

for (int i = 0; i < n - 1; i++) {
int minIndex = i;

for (int j = i + 1; j < n; j++) {
if (arr[j] < arr[minIndex]) {
minIndex = j;
}
}

swap(arr[i], arr[minIndex]);
}
}

void insertionSort(vector<int>& arr) {
int n = arr.size();

for (int i = 1; i < n; i++) {
int key = arr[i];
int j = i - 1;

while (j >= 0 && arr[j] > key) {
arr[j + 1] = arr[j];
j--;
}

arr[j + 1] = key;
}
}

